import sys

def sum_integers(tokens):
    total = 0
    for t in tokens:
        try:
            total += int(t)
        except ValueError:
            pass
    return total

lines = sys.stdin.read().splitlines()
if not lines:
    sys.exit()
T = int(lines[0].strip())
outputs = []
for i in range(1, T + 1):
    tokens = lines[i].split() if i < len(lines) else []
    outputs.append(str(sum_integers(tokens)))
print('\n'.join(outputs))

