const fs = require('fs');
const input = fs.readFileSync(0, 'utf-8').trimEnd().split('\n');
if (input.length === 0) process.exit(0);
const T = parseInt(input[0].trim(), 10);
let results = [];
for (let i = 1; i <= T; i++) {
  const line = input[i] || '';
  const tokens = line.trim().split(/\s+/).filter(Boolean);
  let sum = 0;
  for (const tok of tokens) {
    const num = Number(tok);
    if (!Number.isNaN(num) && Number.isInteger(num)) sum += num;
  }
  results.push(String(sum));
}
console.log(results.join('\n'));

